    grouped_results = defaultdict(lambda: {
        'count': 0,
        'total_score': 0.0,
        'max_score': float('-inf'),
        'min_score': float('inf'),
        'custom_stats': {}
    })

    # Iterate through each SearchResult
    for result in search_results:
        # Extract group value from metadata
        metadata = result.metadata
        group_value = metadata.get(group_by_field)

        # Handle missing grouping field values
