            group_value = 'unknown'

        # Collect statistics for the group
        group_data = grouped_results[group_value]
        group_data['count'] += 1
        group_data['total_score'] += result.score

        # Update max and min scores
        if result.score > group_data['max_score']:
            group_data['max_score'] = result.score
        if result.score < group_data['min_score']:
            group_data['min_score'] = result.score

    # Calculate default statistics
    for group_value, data in grouped_results.items():
        if data['count'] > 0:
            data['avg_score'] = data['total_score'] / data['count']
        else:
            data['avg_score'] = 0.0

    # Apply custom aggregation functions if provided
    if aggregation_funcs:
        for group_value, data in grouped_results.items():
            results_for_group = [
                result for result in search_results 
                if result.metadata.get(group_by_field) == group_value
            ]
            for field_name, func in aggregation_funcs.items():
                try:
                    data['custom_stats'][field_name] = func(results_for_group)
                except Exception as e:
                    # Handle cases where aggregation might fail
                    data['custom_stats'][field_name] = f"Error: {str(e)}"

    # Convert to regular dictionary and return
    return {
        group_value: {
            'count': data['count'],
            'avg_score': data['avg_score'],
            'max_score': data['max_score'],
            'min_score': data['min_score'],
            **data['custom_stats']
        }
        for group_value, data in grouped_results.items()
    }
